import time
import sys
import os
from watchdog.observers import Observer
from watchdog.events import FileSystemEventHandler

class ChangeMonitor(FileSystemEventHandler):
    def on_created(self, event):
        if event.is_directory:
            print(f"Dizin oluşturuldu: {event.src_path}")
        else:
            print(f"Dosya oluşturuldu: {event.src_path}")

    def on_deleted(self, event):
        if event.is_directory:
            print(f"Dizin silindi: {event.src_path}")
        else:
            print(f"Dosya silindi: {event.src_path}")

    def on_modified(self, event):
        if event.is_directory:
            print(f"Dizin değiştirildi: {event.src_path}")
        else:
            print(f"Dosya değiştirildi: {event.src_path}")

    def on_moved(self, event):
        if event.is_directory:
            print(f"Dizin taşındı: {event.src_path} -> {event.dest_path}")
        else:
            print(f"Dosya taşındı: {event.src_path} -> {event.dest_path}")

if __name__ == "__main__":
    path_to_watch = sys.argv[1] if len(sys.argv) > 1 else "."

    if not os.path.isdir(path_to_watch):
        print(f"Hata: '{path_to_watch}' geçerli bir dizin değil.")
        sys.exit(1)

    print(f"Takip ediliyor: {os.path.abspath(path_to_watch)}")

    event_handler = ChangeMonitor()
    observer = Observer()
    observer.schedule(event_handler, path_to_watch, recursive=True)
    observer.start()

    try:
        while True:
            time.sleep(1)
    except KeyboardInterrupt:
        observer.stop()
    observer.join()
    print("Durduruldu.")
